NzEiLCJtZW51X3N1YnNlY3Rpb24iOiJDb2ZmZWUsIG1hdGNoYSBhbmQgdGVhIiwibWVudV9jb250ZXh0IjoiTWFpbiBtZW51IiwicmVjb3JkX3N0YXR1cyI6
ImRyYWZ0IiwicXVhbGl0eV9jb250cm9sIjp7InJlcXVpcmVkX2ZpZWxkc19jb21wbGV0ZSI6ZmFsc2UsIm51dHJpdGlvbl9yZXZpZXdlZCI6ZmFsc2UsImFs
bGVyZ2VuX3Jldmlld2VkIjpmYWxzZSwicHJpY2VfcmV2aWV3ZWQiOnRydWUsImF2YWlsYWJpbGl0eV9yZXZpZXdlZCI6ZmFsc2UsIm5vdGVzIjoiRXh0cmFj
dGVkIGZyb20gSnVuZSAyMDI2IG5hdGlvbmFsIFdhZ2FtYW1hIG1lbnU7IHVuc3VwcG9ydGVkIGZpZWxkcyByZW1haW4gYmxhbmsuIn19fX1d
$payload$, 'base64'),
    'UTF8'
  )::jsonb;
  target_restaurant_id bigint;
  item jsonb;
  imported_dish_id bigint;
  next_dish_id bigint;
  eat_in_price numeric;
  price_valid_from date;
BEGIN
  INSERT INTO public.restaurants (
    name, chain_name, branch_name, area, cuisine, latitude, longitude,
    city, country_code, description
  )
  VALUES (
    'Wagamama',
    'Wagamama',
    'Oxford',
    'Market Street',
    'Japanese-inspired Asian',
    51.75287743021624,
    -1.2574165210949104,
    'Oxford',
    'GB',
    'Casual Japanese-inspired restaurant serving ramen, rice dishes, curries, noodles, sides and drinks.'
  )
  ON CONFLICT (name) DO UPDATE SET
    chain_name = EXCLUDED.chain_name,
    branch_name = EXCLUDED.branch_name,
    area = EXCLUDED.area,
    cuisine = EXCLUDED.cuisine,
    latitude = EXCLUDED.latitude,
    longitude = EXCLUDED.longitude,
    city = EXCLUDED.city,
    country_code = EXCLUDED.country_code,
    description = EXCLUDED.description
  RETURNING id INTO target_restaurant_id;

  SELECT COALESCE(MAX(id), 0) + 1
  INTO next_dish_id
  FROM public.dishes;

  FOR item IN SELECT value FROM jsonb_array_elements(payload)
  LOOP
    eat_in_price := (item #>> '{pricing,current,eat_in}')::numeric;
    price_valid_from := COALESCE(
      NULLIF(item #>> '{pricing,current,valid_from}', '')::date,
      NULLIF(item #>> '{data_sources,pricing,verified_on}', '')::date,
      CURRENT_DATE
    );

    INSERT INTO public.dishes (
      id, restaurant_id, name, price, description, official_description,
      short_description, course, menu_position, meal_occasions, ingredients,
      cooking_methods, serving_style, cultural_origin, historical_notes,
      portion_category, weight_g, volume_ml, piece_count,
      estimated_satiety_score, suitable_for_sharing, people_served,
      nutrition, diets, dietary_flags, allergens, allergen_details,
      sensory_profile, ingredient_profile, recommendation_metadata,
      availability, hidden_search_tokens, official_image_url, visual_metadata,
      derived_features, data_sources, sponsored
    )
    VALUES (
      next_dish_id,
      target_restaurant_id,
      item #>> '{dish,name}',
      eat_in_price,
      COALESCE(item #>> '{dish,official_menu_description}', ''),
      item #>> '{dish,official_menu_description}',
      item #>> '{dish,short_user_friendly_description}',
      item #>> '{dish,menu_section}',
      (item #>> '{dish,menu_position}')::integer,
      ARRAY(SELECT jsonb_array_elements_text(COALESCE(item #> '{dish,meal_occasions}', '[]'::jsonb))),
      ARRAY(SELECT jsonb_array_elements_text(COALESCE(item #> '{dish,ingredients}', '[]'::jsonb))),
      ARRAY(SELECT jsonb_array_elements_text(COALESCE(item #> '{dish,cooking_methods}', '[]'::jsonb))),
      item #>> '{dish,serving_style}',
      item #>> '{dish,cultural_origin}',
      item #>> '{dish,historical_notes}',
      item #>> '{portion,category}',
      (item #>> '{portion,weight_g}')::numeric,
      NULLIF(regexp_replace(COALESCE(item #>> '{portion,volume_ml}', ''), '[^0-9.]', '', 'g'), '')::numeric,
      (item #>> '{portion,piece_count}')::integer,
      (item #>> '{portion,estimated_satiety_score}')::numeric,
      (item #>> '{portion,suitable_for_sharing}')::boolean,
      (item #>> '{portion,people_served}')::numeric,
      COALESCE(item->'nutrition_values', '{}'::jsonb),
      ARRAY(SELECT jsonb_array_elements_text(COALESCE(item #> '{dietary,flags}', '[]'::jsonb))),
      ARRAY(SELECT jsonb_array_elements_text(COALESCE(item #> '{dietary,flags}', '[]'::jsonb))),
      ARRAY(SELECT jsonb_array_elements_text(COALESCE(item #> '{allergen_details,official_allergens}', '[]'::jsonb))),
      COALESCE(item->'allergen_details', '{}'::jsonb),
      COALESCE(item->'sensory_profile', '{}'::jsonb),
      COALESCE(item->'ingredient_profile', '{}'::jsonb),
      COALESCE(item->'recommendation_metadata', '{}'::jsonb),
      COALESCE(item->'availability', '{}'::jsonb),
      ARRAY(SELECT jsonb_array_elements_text(COALESCE(item #> '{search_metadata,hidden_descriptors}', '[]'::jsonb))),
      item #>> '{visual_information,official_image_url}',
      COALESCE(item->'visual_information', '{}'::jsonb),
      COALESCE(item->'derived_features', '{}'::jsonb),
      COALESCE(item->'data_sources', '{}'::jsonb),
      false
    )
    ON CONFLICT (restaurant_id, name) DO UPDATE SET
      price = EXCLUDED.price,
      description = EXCLUDED.description,
      official_description = EXCLUDED.official_description,
      short_description = EXCLUDED.short_description,
      course = EXCLUDED.course,
      menu_position = EXCLUDED.menu_position,
      meal_occasions = EXCLUDED.meal_occasions,
      ingredients = EXCLUDED.ingredients,
      cooking_methods = EXCLUDED.cooking_methods,
      serving_style = EXCLUDED.serving_style,
      cultural_origin = EXCLUDED.cultural_origin,
      historical_notes = EXCLUDED.historical_notes,
      portion_category = EXCLUDED.portion_category,
      weight_g = EXCLUDED.weight_g,
      volume_ml = EXCLUDED.volume_ml,
      piece_count = EXCLUDED.piece_count,
      estimated_satiety_score = EXCLUDED.estimated_satiety_score,
      suitable_for_sharing = EXCLUDED.suitable_for_sharing,
      people_served = EXCLUDED.people_served,
      nutrition = EXCLUDED.nutrition,
      diets = EXCLUDED.diets,
      dietary_flags = EXCLUDED.dietary_flags,
      allergens = EXCLUDED.allergens,
      allergen_details = EXCLUDED.allergen_details,
      sensory_profile = EXCLUDED.sensory_profile,
      ingredient_profile = EXCLUDED.ingredient_profile,
      recommendation_metadata = EXCLUDED.recommendation_metadata,
      availability = EXCLUDED.availability,
      hidden_search_tokens = EXCLUDED.hidden_search_tokens,
      official_image_url = EXCLUDED.official_image_url,
      visual_metadata = EXCLUDED.visual_metadata,
      derived_features = EXCLUDED.derived_features,
      data_sources = EXCLUDED.data_sources
    RETURNING id INTO imported_dish_id;

    next_dish_id := next_dish_id + 1;

    INSERT INTO public.dish_price_history (
      dish_id, service_type, price, currency, region, valid_from
    )
    VALUES (
      imported_dish_id,
      'eat_in',
      eat_in_price,
      COALESCE(NULLIF(item #>> '{pricing,currency}', ''), 'GBP'),
      NULLIF(item #>> '{pricing,current,region}', ''),
      price_valid_from
    )
    ON CONFLICT (dish_id, service_type, region, valid_from) DO UPDATE SET
      price = EXCLUDED.price,
      currency = EXCLUDED.currency;
  END LOOP;
END
$import$;
